function Decode-IL {
    param([byte[]] $il, [string] $methodName)
    Write-Host ("=== IL DECODE: " + $methodName + " ===")
    $i = 0
    while ($i -lt $il.Length) {
        $pos = $i
        $b = $il[$i]; $i++
        $op = ""; $operandStr = ""
        if ($b -eq 0xFE) {
            $b2 = $il[$i]; $i++
            $op = switch ($b2) {
                0x01{"ceq"} 0x02{"cgt"} 0x03{"cgt.un"} 0x04{"clt"} 0x05{"clt.un"}
                0x06{"ldftn"} 0x15{"initobj"} 0x16{"constrained."}
                default{"FE." + $b2.ToString("X2")}
            }
            if ($b2 -in @(0x15,0x16,0x06)) { $tok=[BitConverter]::ToInt32($il,$i);$i+=4;$operandStr=" 0x"+$tok.ToString("X8") }
            Write-Host ("{0:X4}: {1}{2}" -f $pos,$op,$operandStr); continue
        }
        $op = switch ($b) {
            0x00{"nop"} 0x02{"ldarg.0"} 0x03{"ldarg.1"} 0x04{"ldarg.2"} 0x05{"ldarg.3"}
            0x06{"ldloc.0"} 0x07{"ldloc.1"} 0x08{"ldloc.2"} 0x09{"ldloc.3"}
            0x0A{"stloc.0"} 0x0B{"stloc.1"} 0x0C{"stloc.2"} 0x0D{"stloc.3"}
            0x0E{"ldarg.s"} 0x10{"starg.s"} 0x11{"ldloc.s"} 0x12{"ldloca.s"} 0x13{"stloc.s"}
            0x14{"ldnull"} 0x15{"ldc.i4.m1"}
            0x16{"ldc.i4.0"} 0x17{"ldc.i4.1"} 0x18{"ldc.i4.2"} 0x19{"ldc.i4.3"}
            0x1A{"ldc.i4.4"} 0x1B{"ldc.i4.5"} 0x1C{"ldc.i4.6"} 0x1D{"ldc.i4.7"} 0x1E{"ldc.i4.8"}
            0x1F{"ldc.i4.s"} 0x20{"ldc.i4"} 0x22{"ldc.r8"}
            0x25{"dup"} 0x26{"pop"}
            0x28{"call"} 0x2A{"ret"}
            0x2B{"br.s"} 0x2C{"brfalse.s"} 0x2D{"brtrue.s"}
            0x2E{"beq.s"} 0x2F{"bge.s"} 0x30{"bgt.s"} 0x31{"ble.s"} 0x32{"blt.s"}
            0x33{"bne.un.s"} 0x34{"bge.un.s"} 0x35{"bgt.un.s"} 0x36{"ble.un.s"} 0x37{"blt.un.s"}
            0x38{"br"} 0x39{"brfalse"} 0x3A{"brtrue"}
            0x3B{"beq"} 0x3C{"bge"} 0x3D{"bgt"} 0x3E{"ble"} 0x3F{"blt"} 0x40{"bne.un"}
            0x51{"ldind.ref"} 0x52{"stind.ref"}
            0x58{"add"} 0x59{"sub"} 0x5A{"mul"} 0x5B{"div"}
            0x69{"conv.i8"} 0x6A{"conv.i4"} 0x6B{"conv.r8"}
            0x6F{"callvirt"} 0x72{"ldstr"} 0x73{"newobj"}
            0x74{"castclass"} 0x75{"isinst"}
            0x7B{"ldfld"} 0x7C{"ldflda"} 0x7D{"stfld"}
            0x7E{"ldsfld"} 0x7F{"ldsflda"} 0x80{"stsfld"} 0x81{"stobj"}
            0x8C{"box"} 0x8D{"newarr"} 0x8E{"ldlen"}
            0x9A{"ldelem.ref"} 0x9D{"stelem.ref"} 0xA2{"stelem.ref"} 0xA5{"unbox.any"}
            0xDC{"endfinally"} 0xDD{"leave"} 0xDE{"leave.s"}
            0xD0{"ldtoken"}
            default{"0x"+$b.ToString("X2")}
        }
        switch ($b) {
            {$_ -in @(0x11,0x12,0x13,0x0E,0x10,0x1F,0x2B,0x2C,0x2D,0x2E,0x2F,0x30,0x31,0x32,0x33,0x34,0x35,0x36,0x37,0xDE)} {
                $operand=$il[$i]; $i++; $operandStr=" "+$operand; break
            }
            {$_ -in @(0x28,0x6F,0x73,0x74,0x75,0x7B,0x7C,0x7D,0x7E,0x7F,0x80,0x81,0x8C,0x8D,0xD0,0xA5,0xDD,0x38,0x39,0x3A,0x3B,0x3C,0x3D,0x3E,0x3F,0x40)} {
                $tok=[BitConverter]::ToInt32($il,$i); $i+=4; $operandStr=" 0x"+$tok.ToString("X8"); break
            }
            0x20 { $val=[BitConverter]::ToInt32($il,$i); $i+=4; $operandStr=" "+$val; break }
            0x22 { $val=[BitConverter]::ToDouble($il,$i); $i+=8; $operandStr=" "+$val; break }
        }
        Write-Host ("{0:X4}: {1}{2}" -f $pos,$op,$operandStr)
    }
}

